 26→const PostCards = () => {
 27→    const {session, user, openAuthModal} = useAuth();
 28→    const location = useLocation();
 29→    const outletContext = useOutletContext() || {};
 30→    const { clickOpenSidebar, handleOpenTextEditor } = outletContext;
 31→
 32→    const navigate = useNavigate();
