 48→    const [isSearchFocused, setIsSearchFocused] = useState(false);
 49→    const [searchType, setSearchType] = useState('posts');
 50→    const [repostModalJournal, setRepostModalJournal] = useState(null);
 51→    const [repostToastMessage, setRepostToastMessage] = useState('');
 52→
 53→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 54→    const clickContent = handleCLickContent(navigate);
 55→
 56→    const mutateViews = useAddViewsMutation(session)
 57→
 58→    const handleClickUserProfile = (e, loggedInUserId, clickedUserId, clickedUsername = null) => {
 59→        e.stopPropagation();
 60→        if(!session){
 61→            return openAuthModal();
 62→        }
 63→        handleClickUserProfileOriginal(e, loggedInUserId, clickedUserId, clickedUsername);
 64→    }
 65→
 66→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null) =>{
 67→        e.stopPropagation();
 68→        if(session){
 69→            const formadata = new FormData();
 70→            formadata.append('journalId', journalId);
 71→            mutateViews.mutate(formadata);
 72→        }
 73→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc )
 74→    }
 75→
 76→    const header_links = [
 77→        {label: 'Writings', path: '/home'},
 78→        {label: 'Opinions', path: '/home/opinions'},
 79→    ]
 80→
 81→    const handleClickHeaderLinks = (path) =>{
