 83→    }
 84→
 85→    const handleExpandCanvas = (e, journal) => {
 86→        e.stopPropagation();
 87→        viewContent(
 88→            e,
 89→            journal.content,
 90→            getCanvasPreview(journal?.canvas_doc)?.wholeText || '',
 91→            journal.title,
 92→            journal.users.id,
 93→            journal.users.name,
 94→            journal.users.image_url,
 95→            journal.created_at,
 96→            journal.id,
 97→            journal.has_liked,
 98→            journal.comment_count?.[0]?.count,
 99→            journal.has_bookmarked,
100→            journal.like_count?.[0]?.count,
101→            journal.bookmark_count?.[0]?.count,
102→            journal.users.badge,
103→            journal?.post_type,
104→            journal?.canvas_doc
105→        );
106→    }
107→
108→    const handleRemixCanvas = (e, journal) => {
109→        e.stopPropagation();
110→        if(!session){
111→            openAuthModal();
112→            return;
113→        }
114→
115→        const sourceTitle = typeof journal?.title === 'string' ? journal.title.trim() : '';
116→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
