204→    const userId = user?.userData?.[0]?.id || null;
205→    const isSearchMode = committedSearchQuery.length >= 2;
206→    const isPostSearchMode = isSearchMode && searchType === 'posts';
207→    const isPeopleSearchMode = isSearchMode && searchType === 'people';
208→
209→    useEffect(() => {
210→        const timer = setTimeout(() => {
211→            setDebouncedSearchInput(searchInput.trim());
212→        }, 350);
213→
214→        return () => clearTimeout(timer);
215→    }, [searchInput]);
216→
217→    const {
218→        data,
219→        fetchNextPage,
220→        hasNextPage,
221→        isFetchingNextPage,
222→        isLoading: isFeedLoading,
223→    } = useInfiniteQuery({
224→        queryKey: ['journals', userId],
225→        queryFn: ({pageParam = null}) => getJournals(pageParam, 5, userId),
226→        getNextPageParam: (lastPage) => {
227→            if(lastPage?.hasMore) {
228→                const lastJournal = lastPage?.data[lastPage?.data?.length - 1]; //get the last array of object using index
229→                return new Date(lastJournal.created_at).toISOString();
230→            }
231→            return undefined;
232→        } ,
233→        refetchOnWindowFocus: false
234→    })
235→
236→    const {
237→        data: searchData,
238→        isLoading: isSearchLoading,
239→        isFetching: isSearchFetching,
240→        error: searchError,
241→    } = useQuery({
242→        queryKey: ['journals-search', userId, committedSearchQuery],
243→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
244→        enabled: isPostSearchMode,
245→        refetchOnWindowFocus: false,
246→        staleTime: 15 * 1000,
247→    });
248→
249→    const {
250→        data: suggestionData,
251→        isLoading: isSuggestionsLoading,
252→    } = useQuery({
253→        queryKey: ['journals-suggestions', userId, debouncedSearchInput],
254→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
255→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === 'posts',
256→        refetchOnWindowFocus: false,
257→        staleTime: 10 * 1000,
258→    });
259→
260→    const {
261→        data: userSearchData,
262→        isLoading: isUserSearchLoading,
263→        isFetching: isUserSearchFetching,
264→        error: userSearchError,
265→    } = useQuery({
266→        queryKey: ['users-search', committedSearchQuery],
267→        queryFn: () => searchUsers(committedSearchQuery, 10),
268→        enabled: isPeopleSearchMode,
269→        refetchOnWindowFocus: false,
270→        staleTime: 10 * 1000,
271→    });
272→
273→    const {
274→        data: userSuggestionData,
275→        isLoading: isUserSuggestionsLoading,
276→    } = useQuery({
277→        queryKey: ['users-suggestions', debouncedSearchInput],
278→        queryFn: () => searchUsers(debouncedSearchInput, 6),
279→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === 'people',
280→        refetchOnWindowFocus: false,
281→        staleTime: 10 * 1000,
282→    });
283→
284→    const handleClickSettings = (e, postId) =>{
285→        e.stopPropagation();
286→        setPostIdSettings(postId === postIdSettings ? null : postId)
287→    }
288→
289→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
290→
291→    const handleClickLike = async (journalId, receiverId) => {
292→        if(!session) return openAuthModal();
293→        console.log(journalId)
294→        mutationLike.mutate({journalId, receiverId}) //passing this into mutationFn {journalId: the id}
295→    }
296→
297→
298→    const mutationBookmark = useBookMarkMutation(session, userId);
299→
300→    const handleClickBookmark = async (journalId) => {
301→        if(!session) return openAuthModal();
302→        console.log(journalId)
303→        // mutationBookmark.mutate({journalId});
304→        const response = await mutationBookmark.mutateAsync({journalId})
305→
306→        if(timeOutRef.current){
307→            clearTimeout(timeOutRef.current);
308→        }
309→        if(response.message === 'success'){
310→            setBookmarkedMessage('Post was added to your Bookmarks')
311→            setShowBookmarkedMessage(journalId);
312→            timeOutRef.current = setTimeout(() =>{
313→                setShowBookmarkedMessage(null)
314→                setBookmarkedMessage('')
315→            }, 2500)
316→        } else {
317→            setBookmarkedMessage('Post was removed from your Bookmarks')
318→            setShowBookmarkedMessage(journalId);
319→            timeOutRef.current = setTimeout(() =>{
320→                setShowBookmarkedMessage(null)
321→                setBookmarkedMessage('')
322→            }, 2500)
323→        }
324→        console.log(response.message);
325→    }
326→
327→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
328→
329→    const handleSubmitSearch = (rawQuery) => {
330→        const normalizedQuery = typeof rawQuery === 'string' ? rawQuery.trim() : '';
331→        if(normalizedQuery.length < 2){
332→            setCommittedSearchQuery('');
333→            return;
334→        }
335→
336→        setCommittedSearchQuery(normalizedQuery);
337→        setSearchInput(normalizedQuery);
338→        setIsSearchFocused(false);
339→    };
340→
341→    const handleClearSearch = () => {
342→        setSearchInput('');
343→        setDebouncedSearchInput('');
344→        setCommittedSearchQuery('');
345→        setIsSearchFocused(false);
346→        setSearchType('posts');
347→    };
348→
349→    const handleSearchInputKeyDown = (e) => {
350→        if(e.key === 'Enter'){
351→            e.preventDefault();
352→            handleSubmitSearch(searchInput);
353→        }
354→
355→        if(e.key === 'Escape'){
356→            setIsSearchFocused(false);
357→        }
358→    };
359→
360→    const handleClickSuggestion = (journal) => {
361→        if(!journal?.id){
362→            return;
363→        }
364→        setIsSearchFocused(false);
365→        if(journal?.title){
366→            setSearchInput(journal.title);
367→            setDebouncedSearchInput(journal.title);
368→        }
369→        navigate(`/home/post/${journal.id}`);
370→    };
371→
372→    const handleClickUserSuggestion = (e, person) => {
373→        if(!person?.id){
374→            return;
375→        }
376→        setIsSearchFocused(false);
377→        handleClickUserProfile(e, user?.userData?.[0]?.id, person.id, person.username);
378→    };
379→
380→    const handleVisitFreedomWall = () => {
381→        navigate('/home/freedom-wall');
382→    };
383→
384→    useEffect(() => {
385→        const handleOutsideSearchClick = (e) => {
386→            if(searchShellRef.current && !searchShellRef.current.contains(e.target)){
387→                setIsSearchFocused(false);
388→            }
389→        };
390→
391→        window.addEventListener('mousedown', handleOutsideSearchClick);
392→        return () => window.removeEventListener('mousedown', handleOutsideSearchClick);
393→    }, []);
394→
395→    useEffect(() =>{
396→        if(!isSearchMode && inView && hasNextPage && !isFetchingNextPage) {
397→            fetchNextPage();
398→        }
399→    }, [inView, fetchNextPage, hasNextPage, isFetchingNextPage, isSearchMode])
400→
401→
402→    useEffect(() => {
403→       const handleClickOutside = (e) =>{
404→        if(modalRef.current && !modalRef.current.contains(e.target)){
405→            setPostIdSettings(null)
406→        }
407→       }
408→       window.addEventListener('click', handleClickOutside)
409→
410→       return() => {
411→        window.removeEventListener('click', handleClickOutside)
412→       }
413→    }, [])
414→
415→    useEffect(() =>{
416→        const scroll = (e) =>{
417→            setShowHeaders(!showHeaders)
418→
419→            if(timeOutRef.current){
420→                clearTimeout(timeOutRef.current);
421→            }
422→            timeOutRef.current = setTimeout(() => {
423→                setShowHeaders(showHeaders)
424→            }, 100);
425→        }
426→        document.addEventListener('scroll', scroll, true);
427→        return() =>{
428→            if(timeOutRef.current){
429→                clearTimeout(timeOutRef.current);
430→            }
431→            document.removeEventListener('scroll', scroll, true)
432→        }
433→    }, [])
434→
435→    const feedJournals = data?.pages?.flatMap((page) => page.data || []) || [];
436→    const searchedJournals = searchData?.data || [];
437→    const searchedUsers = userSearchData?.data || [];
438→    const suggestionItems = searchType === 'people'
439→        ? (userSuggestionData?.data || [])
440→        : (suggestionData?.data || []);
441→    const isSuggestionsPending = searchType === 'people'
442→        ? isUserSuggestionsLoading
443→        : isSuggestionsLoading;
444→    const journals = isSearchMode ? searchedJournals : feedJournals;
445→    const isLoading = isPostSearchMode
446→        ? isSearchLoading
447→        : isPeopleSearchMode
448→            ? isUserSearchLoading
449→            : isFeedLoading;
450→    const activeSearchError = searchType === 'people' ? userSearchError : searchError;
451→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
452→
453→    if(isLoading) {
454→        return(
455→            <>
456→            <div className="postcards-parent-loading-container">
457→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
458→            </div>
459→            </>
460→        )
461→    }
462→
463→    return(
464→        <>
465→        <div className="mobile-top-header">
466→            <span className="mobile-brand-text">iskrib</span>
467→            {clickOpenSidebar && (
468→                <button className="mobile-header-profile-btn" onClick={clickOpenSidebar}>
469→                    <img src={user?.userData?.[0]?.image_url || '/assets/profile.jpg'} alt="profile" />
470→                </button>
