    }
    .mobile-write-btn svg{
        flex-shrink: 0;
    }

    /* ── Freedom Wall banner pill ── */
    .mobile-fw-banner{
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 0.4rem;
        margin: 0.5rem 0.75rem 0;
