}
.search-nav-stories:hover{
    background: linear-gradient(135deg, rgba(95, 146, 255, 0.18), rgba(95, 146, 255, 0.12));
    box-shadow: 0 0 10px rgba(95, 146, 255, 0.15);
}
.search-mode-pill{
